/* register access functions for CAL_RAM_XO32M_CLOAD_COMP_LUT */
/* cload compensation for the XTAL type and PCB layout as function of the temperature in 10C steps */
#define GP_WB_READ_CAL_RAM_XO32M_CLOAD_COMP_LUT() \
        ((UInt32)CAL_RAM_REGMAP->xo32m_cload_comp_lut.reg32[0])

#define GP_WB_WRITE_CAL_RAM_XO32M_CLOAD_COMP_LUT(val) \
      CAL_RAM_REGMAP->xo32m_cload_comp_lut.reg32[0] = (val)

/* xo32m cload compensation value for the lowest temperature range (-30C and below ) */
#define GP_WB_READ_CAL_RAM_XO32M_CLOAD_COMP_0() \
        (GP_WB_S8(((UInt8)((CAL_RAM_REGMAP->xo32m_cload_comp_lut.reg32[0]) & 0xFF)), 8))

#define GP_WB_GET_CAL_RAM_XO32M_CLOAD_COMP_0_FROM_XO32M_CLOAD_COMP_LUT(tmp) \
        (GP_WB_S8(((tmp) & 0xFF), 8))

#define GP_WB_WRITE_CAL_RAM_XO32M_CLOAD_COMP_0(val) do { \
          CAL_RAM_REGMAP->xo32m_cload_comp_lut.reg8[0] = (UInt8)((val)); \
        } while (0)

#define GP_WB_SET_CAL_RAM_XO32M_CLOAD_COMP_0_TO_XO32M_CLOAD_COMP_LUT(tmp, val) do { \
          GP_WB_SIZE_CHECK_U32(tmp); \
          (tmp) &= 0xFFFFFF00; \
          (tmp) |= (((Int32)(val)) & 0x000000FF); \
        } while (0)

/* xo32m cload compensation value for temperature range (-30C to -20C) */
#define GP_WB_READ_CAL_RAM_XO32M_CLOAD_COMP_1() \
        (GP_WB_S8(((UInt8)(((CAL_RAM_REGMAP->xo32m_cload_comp_lut.reg32[0]) >> 8) & 0xFF)), 8))

#define GP_WB_GET_CAL_RAM_XO32M_CLOAD_COMP_1_FROM_XO32M_CLOAD_COMP_LUT(tmp) \
        (GP_WB_S8((((tmp) >> 8) & 0xFF), 8))

#define GP_WB_WRITE_CAL_RAM_XO32M_CLOAD_COMP_1(val) do { \
          CAL_RAM_REGMAP->xo32m_cload_comp_lut.reg8[1] = (UInt8)((val)); \
        } while (0)

#define GP_WB_SET_CAL_RAM_XO32M_CLOAD_COMP_1_TO_XO32M_CLOAD_COMP_LUT(tmp, val) do { \
          GP_WB_SIZE_CHECK_U32(tmp); \
          (tmp) &= 0xFFFF00FF; \
          (tmp) |= ((((Int32)(val)) << 8) & 0x0000FF00); \
        } while (0)

/* xo32m cload compensation value for temperature range (-20C to -10C) */
#define GP_WB_READ_CAL_RAM_XO32M_CLOAD_COMP_2() \
