/***************************
 * regmap: appuc
 ***************************/

/* Offset in 256 byte multiples for the vector table */
#define GP_WB_READ_APPUC_VECTOR_TABLE_OFFSET() \
        ((UInt32)(APPUC_REGMAP->vector_table_offset.reg32[0]))

#define GP_WB_WRITE_APPUC_VECTOR_TABLE_OFFSET(val) do { \
          GP_WB_RANGE_CHECK(val, 0xFFFFFF); \
          APPUC_REGMAP->vector_table_offset.reg32[0] = (val); \
        } while (0)


/* Should be set to the value in order to a 10 ms delay from the FCLK. So needs to change when FCLK changes frequency */
#define GP_WB_READ_APPUC_SYSTICK_CALIB() \
        ((UInt32)(APPUC_REGMAP->systick_calib.reg32[0]))

#define GP_WB_WRITE_APPUC_SYSTICK_CALIB(val) do { \
          GP_WB_RANGE_CHECK(val, 0xFFFFFF); \
          APPUC_REGMAP->systick_calib.reg32[0] = (val); \
        } while (0)


/* register access functions for APPUC_STATUS */
#define GP_WB_READ_APPUC_STATUS() \
        ((UInt8)APPUC_REGMAP->status.reg32[0])

/* Indicates that the processor is in sleep mode (WFI/WFE instruction) */
#define GP_WB_READ_APPUC_ASLEEP() \
        ((UInt8)((APPUC_REGMAP->status.reg32[0]) & 0x01))

#define GP_WB_GET_APPUC_ASLEEP_FROM_STATUS(tmp) \
        ((tmp) & 0x01)

/* Indicates that the processor is in deep sleep mode (WFI/WFE with SCR deep sleep mask set) */
#define GP_WB_READ_APPUC_INDEEPSLEEP() \
        ((UInt8)(((APPUC_REGMAP->status.reg32[0]) >> 1) & 0x01))

#define GP_WB_GET_APPUC_INDEEPSLEEP_FROM_STATUS(tmp) \
        (((tmp) >> 1) & 0x01)

/* Indicates the processor is halted */
#define GP_WB_READ_APPUC_HALTED() \
        ((UInt8)(((APPUC_REGMAP->status.reg32[0]) >> 2) & 0x01))

#define GP_WB_GET_APPUC_HALTED_FROM_STATUS(tmp) \
        (((tmp) >> 2) & 0x01)

/* Indicates the APPUC is hold in reset by an external signal */
#define GP_WB_READ_APPUC_EXTERNAL_RESET() \
        ((UInt8)(((APPUC_REGMAP->status.reg32[0]) >> 3) & 0x01))

#define GP_WB_GET_APPUC_EXTERNAL_RESET_FROM_STATUS(tmp) \
        (((tmp) >> 3) & 0x01)

/* Indicates the APPUC sync down bridge is in bypass mode */
#define GP_WB_READ_APPUC_SYNC_DOWN_IN_BYPASS() \
        ((UInt8)(((APPUC_REGMAP->status.reg32[0]) >> 4) & 0x01))

#define GP_WB_GET_APPUC_SYNC_DOWN_IN_BYPASS_FROM_STATUS(tmp) \
        (((tmp) >> 4) & 0x01)

/* Indicates the APPUC cache is doing an operation (flushing, line filling, data lookup, ...) */
#define GP_WB_READ_APPUC_CACHE_STATUS() \
        ((UInt8)(((APPUC_REGMAP->status.reg32[0]) >> 5) & 0x01))

#define GP_WB_GET_APPUC_CACHE_STATUS_FROM_STATUS(tmp) \
        (((tmp) >> 5) & 0x01)


/* register access functions for APPUC_CFG */
#define GP_WB_READ_APPUC_CFG() \
        ((UInt16)APPUC_REGMAP->cfg.reg32[0])

#define GP_WB_WRITE_APPUC_CFG(val) \
      APPUC_REGMAP->cfg.reg32[0] = (val)

/* When 1, keeps appuc in reset. */
#define GP_WB_READ_APPUC_MAIN_RESET() \
        ((UInt8)((APPUC_REGMAP->cfg.reg32[0]) & 0x01))

#define GP_WB_GET_APPUC_MAIN_RESET_FROM_CFG(tmp) \
        ((tmp) & 0x01)

#define GP_WB_WRITE_APPUC_MAIN_RESET(val) do { \
          GP_WB_RANGE_CHECK(val, 0x01); \
          UInt32 halprop_h_tmp = (APPUC_REGMAP->cfg.reg32[0]); \
          halprop_h_tmp = (halprop_h_tmp & ~(0x00000001)) | ((((val)) << 0) & (0x00000001)); \
          APPUC_REGMAP->cfg.reg32[0] = halprop_h_tmp; \
        } while (0)

#define GP_WB_SET_APPUC_MAIN_RESET_TO_CFG(tmp, val) do { \
          GP_WB_SIZE_CHECK_U16(tmp); \
          GP_WB_RANGE_CHECK(val, 0x01); \
          (tmp) &= 0x01FE; \
          (tmp) |= ((UInt16)(val)); \
        } while (0)

/* When 1, the appuc cache is in reset. */
#define GP_WB_READ_APPUC_RESET_CACHE() \
        ((UInt8)(((APPUC_REGMAP->cfg.reg32[0]) >> 1) & 0x01))

#define GP_WB_GET_APPUC_RESET_CACHE_FROM_CFG(tmp) \
        (((tmp) >> 1) & 0x01)

#define GP_WB_WRITE_APPUC_RESET_CACHE(val) do { \
          GP_WB_RANGE_CHECK(val, 0x01); \
          UInt32 halprop_h_tmp = (APPUC_REGMAP->cfg.reg32[0]); \
          halprop_h_tmp = (halprop_h_tmp & ~(0x00000002)) | ((((val) << 1) << 0) & (0x00000002)); \
          APPUC_REGMAP->cfg.reg32[0] = halprop_h_tmp; \
        } while (0)

#define GP_WB_SET_APPUC_RESET_CACHE_TO_CFG(tmp, val) do { \
          GP_WB_SIZE_CHECK_U16(tmp); \
          GP_WB_RANGE_CHECK(val, 0x01); \
          (tmp) &= 0x01FD; \
          (tmp) |= (((UInt16)(val)) << 1); \
        } while (0)

/* When 1, allows the appuc to sleep */
#define GP_WB_READ_APPUC_SLEEP_ENABLE() \
        ((UInt8)(((APPUC_REGMAP->cfg.reg32[0]) >> 2) & 0x01))

#define GP_WB_GET_APPUC_SLEEP_ENABLE_FROM_CFG(tmp) \
        (((tmp) >> 2) & 0x01)

#define GP_WB_WRITE_APPUC_SLEEP_ENABLE(val) do { \
