#define GP_WB_SET_SPI_M_LSB_FIRST_TO_CONF(tmp, val) do { \
          GP_WB_SIZE_CHECK_U16(tmp); \
          GP_WB_RANGE_CHECK(val, 0x01); \
          (tmp) &= 0x7F7F; \
          (tmp) |= (((UInt16)(val)) << 7); \
        } while (0)

/* SCLK clock frequency divider (limited to range 0 .. 8): 64MHz / 2**sclk_freq */
