          GP_WB_RANGE_CHECK(val, 0x01); \
          UInt32 halprop_h_tmp = (IR_REGMAP->modulation_control_1.reg32[0]); \
          halprop_h_tmp = (halprop_h_tmp & ~(0x00000002)) | ((((val) << 1) << 0) & (0x00000002)); \
          IR_REGMAP->modulation_control_1.reg32[0] = halprop_h_tmp; \
