/* register access functions for I2C_SL_STATUS */
#define GP_WB_READ_I2C_SL_STATUS() \
        ((UInt8)I2C_SL_REGMAP->status.reg32[0])

/* Status of the RnW bit of the last successful slave addressing. When 0, this indicated master-to-slave direction. When 1, this indicated slave-to-master direction. The flag is updated on each slad event. */
