#define GP_WB_READ_I2C_SL_UNMASKED_START_INTERRUPT() \
        ((UInt8)(((I2C_SL_REGMAP->unmasked_interrupts.reg32[0]) >> 2) & 0x01))

#define GP_WB_GET_I2C_SL_UNMASKED_START_INTERRUPT_FROM_UNMASKED_INTERRUPTS(tmp) \
        (((tmp) >> 2) & 0x01)

