/* register access functions for HR_ADC_CHANNEL_CONF */
#define GP_WB_READ_HR_ADC_CHANNEL_CONF() \
        ((UInt8)HR_ADC_REGMAP->channel_conf.reg32[0])

#define GP_WB_WRITE_HR_ADC_CHANNEL_CONF(val) \
      HR_ADC_REGMAP->channel_conf.reg32[0] = (val)

/* selection of N-input of HR GP-ADC */
#define GP_WB_READ_HR_ADC_N_SEL() \
        ((UInt8)((HR_ADC_REGMAP->channel_conf.reg32[0]) & 0x03))

#define GP_WB_GET_HR_ADC_N_SEL_FROM_CHANNEL_CONF(tmp) \
        ((tmp) & 0x03)

#define GP_WB_WRITE_HR_ADC_N_SEL(val) do { \
          GP_WB_RANGE_CHECK(val, 0x03); \
          UInt32 halprop_h_tmp = (HR_ADC_REGMAP->channel_conf.reg32[0]); \
          halprop_h_tmp = (halprop_h_tmp & ~(0x00000003)) | ((((val)) << 0) & (0x00000003)); \
          HR_ADC_REGMAP->channel_conf.reg32[0] = halprop_h_tmp; \
        } while (0)

#define GP_WB_SET_HR_ADC_N_SEL_TO_CHANNEL_CONF(tmp, val) do { \
          GP_WB_SIZE_CHECK_U8(tmp); \
          GP_WB_RANGE_CHECK(val, 0x03); \
          (tmp) &= 0x0C; \
          (tmp) |= ((UInt8)(val)); \
        } while (0)

/* selection of P-input of HR GP-ADC */
#define GP_WB_READ_HR_ADC_P_SEL() \
        ((UInt8)(((HR_ADC_REGMAP->channel_conf.reg32[0]) >> 2) & 0x03))

#define GP_WB_GET_HR_ADC_P_SEL_FROM_CHANNEL_CONF(tmp) \
        (((tmp) >> 2) & 0x03)

#define GP_WB_WRITE_HR_ADC_P_SEL(val) do { \
          GP_WB_RANGE_CHECK(val, 0x03); \
          UInt32 halprop_h_tmp = (HR_ADC_REGMAP->channel_conf.reg32[0]); \
          halprop_h_tmp = (halprop_h_tmp & ~(0x0000000c)) | ((((val) << 2) << 0) & (0x0000000c)); \
          HR_ADC_REGMAP->channel_conf.reg32[0] = halprop_h_tmp; \
        } while (0)

#define GP_WB_SET_HR_ADC_P_SEL_TO_CHANNEL_CONF(tmp, val) do { \
          GP_WB_SIZE_CHECK_U8(tmp); \
          GP_WB_RANGE_CHECK(val, 0x03); \
          (tmp) &= 0x03; \
          (tmp) |= (((UInt8)(val)) << 2); \
        } while (0)


