/* trigger a nvm access, defined by the nvm_config settings when in overrule mode */
#define GP_WB_CMA_MRI_NVM_CMD_TRIGGER() \
        CMA_REGMAP->mri_nvm_cmd_trigger_ctrl.reg32[0] = (0x00000001)

#define GP_WB_SET_CMA_MRI_NVM_CMD_TRIGGER_TO_MRI_NVM_CMD_TRIGGER_CTRL(tmp, val) do { \
          GP_WB_SIZE_CHECK_U8(tmp); \
          GP_WB_RANGE_CHECK(val, 0x01); \
          (tmp) &= 0x3E; \
          (tmp) |= ((UInt8)(val)); \
        } while (0)

/* write interrupt clear */
