#define GP_WB_WRITE_SYSRAM_END_PTR(val) do { \
          GP_WB_RANGE_CHECK(val, 0x3FFF); \
          SYSRAM_REGMAP->end_ptr.reg32[0] = (val); \
        } while (0)


