/* register access functions for SYSRAM_TRIGGERS */
#define GP_WB_WRITE_SYSRAM_TRIGGERS(val) \
      SYSRAM_REGMAP->triggers.reg32[0] = (val)

/* Starts a RAM built in self test */
#define GP_WB_SYSRAM_BIST_START() \
        SYSRAM_REGMAP->triggers.reg32[0] = (0x00000001)

#define GP_WB_SET_SYSRAM_BIST_START_TO_TRIGGERS(tmp, val) do { \
          GP_WB_SIZE_CHECK_U8(tmp); \
          GP_WB_RANGE_CHECK(val, 0x01); \
          (tmp) &= 0x3E; \
          (tmp) |= ((UInt8)(val)); \
        } while (0)

/* Starts a RAM init cycle */
#define GP_WB_SYSRAM_START_INIT() \
        SYSRAM_REGMAP->triggers.reg32[0] = (0x00000002)

#define GP_WB_SET_SYSRAM_START_INIT_TO_TRIGGERS(tmp, val) do { \
          GP_WB_SIZE_CHECK_U8(tmp); \
          GP_WB_RANGE_CHECK(val, 0x01); \
          (tmp) &= 0x3D; \
          (tmp) |= (((UInt8)(val)) << 1); \
        } while (0)

/* Starts a RAM crc calculation */
#define GP_WB_SYSRAM_START_CRC() \
        SYSRAM_REGMAP->triggers.reg32[0] = (0x00000004)

#define GP_WB_SET_SYSRAM_START_CRC_TO_TRIGGERS(tmp, val) do { \
          GP_WB_SIZE_CHECK_U8(tmp); \
          GP_WB_RANGE_CHECK(val, 0x01); \
          (tmp) &= 0x3B; \
          (tmp) |= (((UInt8)(val)) << 2); \
        } while (0)

/* Starts a retention backup cycle */
#define GP_WB_SYSRAM_START_BACKUP() \
        SYSRAM_REGMAP->triggers.reg32[0] = (0x00000008)

#define GP_WB_SET_SYSRAM_START_BACKUP_TO_TRIGGERS(tmp, val) do { \
          GP_WB_SIZE_CHECK_U8(tmp); \
          GP_WB_RANGE_CHECK(val, 0x01); \
          (tmp) &= 0x37; \
          (tmp) |= (((UInt8)(val)) << 3); \
        } while (0)

/* Starts a retention restore cycle */
#define GP_WB_SYSRAM_START_RESTORE() \
        SYSRAM_REGMAP->triggers.reg32[0] = (0x00000010)

#define GP_WB_SET_SYSRAM_START_RESTORE_TO_TRIGGERS(tmp, val) do { \
          GP_WB_SIZE_CHECK_U8(tmp); \
          GP_WB_RANGE_CHECK(val, 0x01); \
          (tmp) &= 0x2F; \
          (tmp) |= (((UInt8)(val)) << 4); \
        } while (0)

