/* Transfer size, 00 : 8bit data transfer. 01 : 16bit data transfer. 10 : 32bit data transfer */
#define GP_WB_READ_USB_SFR_DSIZE() \
        ((UInt8)((USB_SFR_REGMAP->dmactrl.reg8[0]) & 0x03))

