/* key length enumerate : "00" = 128 bit key, "01" = 192 bit key, "10" = 256 bit key */
#define GP_WB_READ_SSP_KEY_LEN() \
        ((UInt8)((SSP_REGMAP->unnamed_reg_ssp_0x0020.reg32[0]) & 0x03))

#define GP_WB_WRITE_SSP_KEY_LEN(val) do { \
          GP_WB_RANGE_CHECK(val, 0x03); \
          UInt32 halprop_h_tmp = (SSP_REGMAP->unnamed_reg_ssp_0x0020.reg32[0]); \
          halprop_h_tmp = (halprop_h_tmp & ~(0x00000003)) | ((((val)) << 0) & (0x00000003)); \
          SSP_REGMAP->unnamed_reg_ssp_0x0020.reg32[0] = halprop_h_tmp; \
        } while (0)

/* Mic length/2 (actual length is the value set by this FIELDerty multiplied by 2) */
#define GP_WB_READ_SSP_MIC_LEN() \
        ((UInt8)(((SSP_REGMAP->unnamed_reg_ssp_0x0020.reg32[0]) >> 2) & 0x0F))

#define GP_WB_WRITE_SSP_MIC_LEN(val) do { \
          GP_WB_RANGE_CHECK(val, 0x0F); \
          UInt32 halprop_h_tmp = (SSP_REGMAP->unnamed_reg_ssp_0x0020.reg32[0]); \
          halprop_h_tmp = (halprop_h_tmp & ~(0x0000003c)) | ((((val) << 2) << 0) & (0x0000003c)); \
          SSP_REGMAP->unnamed_reg_ssp_0x0020.reg32[0] = halprop_h_tmp; \
        } while (0)


