#define GP_WB_SET_QUIC_CHANNEL_0_TRIGGER_SRC_TO_CHANNEL_0_CONF(tmp, val) do { \
          GP_WB_SIZE_CHECK_U16(tmp); \
          (tmp) &= 0x7F00; \
          (tmp) |= ((UInt16)(val)); \
        } while (0)

/* selects the mode (rising edge / falling edge / level / inverted level or both rise and fall) */
#define GP_WB_READ_QUIC_CHANNEL_0_EDGE_SEL() \
        ((UInt8)(((QUIC_REGMAP->channel_0_conf.reg32[0]) >> 8) & 0x07))

#define GP_WB_GET_QUIC_CHANNEL_0_EDGE_SEL_FROM_CHANNEL_0_CONF(tmp) \
        (((tmp) >> 8) & 0x07)

#define GP_WB_WRITE_QUIC_CHANNEL_0_EDGE_SEL(val) do { \
          GP_WB_RANGE_CHECK(val, 0x07); \
          UInt32 halprop_h_tmp = (QUIC_REGMAP->channel_0_conf.reg32[0]); \
          halprop_h_tmp = (halprop_h_tmp & ~(0x00000700)) | ((((val)) << 8) & (0x00000700)); \
          QUIC_REGMAP->channel_0_conf.reg32[0] = halprop_h_tmp; \
        } while (0)

#define GP_WB_SET_QUIC_CHANNEL_0_EDGE_SEL_TO_CHANNEL_0_CONF(tmp, val) do { \
          GP_WB_SIZE_CHECK_U16(tmp); \
          GP_WB_RANGE_CHECK(val, 0x07); \
          (tmp) &= 0x78FF; \
          (tmp) |= (((UInt16)(val)) << 8); \
        } while (0)

/* Determines what speed the trigger source on the channel is expected to do trigger updates */
#define GP_WB_READ_QUIC_CHANNEL_0_SRC_SPEED() \
