/* Flush bit : writing a 1 into this bit, flushes the contents of the tag memories which invalidates the content of cache memory. The read of this bit is always '0'. */
#define GP_WB_READ_APPUC_CACHE_FLUSH() \
        ((UInt8)((APPUC_CACHE_REGMAP->cachectrl.reg32[0]) & 0x01))

#define GP_WB_GET_APPUC_CACHE_FLUSH_FROM_CACHECTRL(tmp) \
        ((tmp) & 0x01)

