/* Sets the 16 bits to shift out of the (24 bit) pcm stream coming from the cic filter and into the data_out registers, this is the value determined of theoretical max value */
#define GP_WB_READ_ASP_PCM_LSB(offset) \
        ((UInt8)((((ASP_REGMAP_T *) (offset))->pcm_conf.reg32[0]) & 0x0F))

#define GP_WB_GET_ASP_PCM_LSB_FROM_PCM_CONF(tmp) \
