/* Starts the interface. Make sure the first databyte is already available in tx_data before enabling the interface. */
#define GP_WB_READ_I2S_ENABLE(offset) \
        ((UInt8)((((I2S_REGMAP_T *) (offset))->config_0.reg32[0]) & 0x01))

#define GP_WB_GET_I2S_ENABLE_FROM_CONFIG_0(tmp) \
        ((tmp) & 0x01)

#define GP_WB_WRITE_I2S_ENABLE(offset, val) do { \
          GP_WB_RANGE_CHECK(val, 0x01); \
          GP_WB_CHECK_OFFSET_I2S(offset); \
          UInt32 halprop_h_tmp = (((I2S_REGMAP_T *) (offset))->config_0.reg32[0]); \
          halprop_h_tmp = (halprop_h_tmp & ~(0x00000001)) | ((((val)) << 0) & (0x00000001)); \
          ((I2S_REGMAP_T *) (offset))->config_0.reg32[0] = halprop_h_tmp; \
        } while (0)

#define GP_WB_SET_I2S_ENABLE_TO_CONFIG_0(tmp, val) do { \
          GP_WB_SIZE_CHECK_U32(tmp); \
          GP_WB_RANGE_CHECK(val, 0x01); \
          (tmp) &= 0x3FFFFF3E; \
          (tmp) |= ((UInt32)(val)); \
        } while (0)

/* Enables the tx fifo interrupts. Allows SW to stop interrupt generation from the SPI master when the I2S is not needed. */
#define GP_WB_READ_I2S_ENABLE_TX_INTERRUPTS(offset) \
        ((UInt8)(((((I2S_REGMAP_T *) (offset))->config_0.reg32[0]) >> 1) & 0x01))

