/* Offset in SCK cycles between the WS toggle and the first data bit. For real I2S mode, this should be 1. */
#define GP_WB_READ_I2S_WS_OFFSET(offset) \
        ((UInt8)(((((I2S_REGMAP_T *) (offset))->config_0.reg32[0]) >> 3) & 0x07))

#define GP_WB_GET_I2S_WS_OFFSET_FROM_CONFIG_0(tmp) \
