/* Length in SCK cycles between two consecutive WS toggles. */
#define GP_WB_READ_I2S_WORD_LEN(offset) \
        ((UInt8)(((((I2S_REGMAP_T *) (offset))->config_0.reg32[0]) >> 16) & 0xFF))

