#define GP_WB_WRITE_I2S_TX_BYTES_RIGHT(offset, val) do { \
          GP_WB_RANGE_CHECK(val, 0x07); \
          GP_WB_CHECK_OFFSET_I2S(offset); \
          UInt32 halprop_h_tmp = (((I2S_REGMAP_T *) (offset))->config_0.reg32[0]); \
          halprop_h_tmp = (halprop_h_tmp & ~(0x38000000)) | ((((val) << 3) << 24) & (0x38000000)); \
          ((I2S_REGMAP_T *) (offset))->config_0.reg32[0] = halprop_h_tmp; \
        } while (0)

#define GP_WB_SET_I2S_TX_BYTES_RIGHT_TO_CONFIG_0(tmp, val) do { \
