/* defines the number of data bits per pixel - Actual number of bits = databits + 1 */
#define GP_WB_READ_RTZ_DATA_BITS(offset) \
        ((UInt16)(((RTZ_REGMAP_T *) (offset))->data_bits.reg32[0]))

#define GP_WB_WRITE_RTZ_DATA_BITS(offset, val) do { \
          GP_WB_RANGE_CHECK(val, 0x01FF); \
          GP_WB_CHECK_OFFSET_RTZ(offset); \
          ((RTZ_REGMAP_T *) (offset))->data_bits.reg32[0] = (val); \
        } while (0)


/* Defines the number of pixels in a sequence - Actual number of pixels = pixels + 1 */
#define GP_WB_READ_RTZ_PIXELS(offset) \
        ((UInt16)(((RTZ_REGMAP_T *) (offset))->pixels.reg32[0]))

#define GP_WB_WRITE_RTZ_PIXELS(offset, val) do { \
          GP_WB_RANGE_CHECK(val, 0x01FF); \
          GP_WB_CHECK_OFFSET_RTZ(offset); \
          ((RTZ_REGMAP_T *) (offset))->pixels.reg32[0] = (val); \
        } while (0)


/* Defines the number of data bits that are sent out, after the regular pixel sequence when enable_trailing_data=1. Actual nr of trailing bits  = trailing_data_bits + 1 */
#define GP_WB_READ_RTZ_TRAILING_DATA_BITS(offset) \
        ((UInt16)(((RTZ_REGMAP_T *) (offset))->trailing_data_bits.reg32[0]))

