/* register access functions for RTZ_TRIGGERS */
#define GP_WB_WRITE_RTZ_TRIGGERS(offset, val) \
      ((RTZ_REGMAP_T *) (offset))->triggers.reg32[0] = (val)

/* starts rtz sequence */
#define GP_WB_RTZ_TRIGGER_SEQUENCE(offset) \
        ((RTZ_REGMAP_T *) (offset))->triggers.reg32[0] = (0x00000001)

#define GP_WB_SET_RTZ_TRIGGER_SEQUENCE_TO_TRIGGERS(tmp, val) do { \
          GP_WB_SIZE_CHECK_U8(tmp); \
          GP_WB_RANGE_CHECK(val, 0x01); \
          (tmp) &= 0x02; \
          (tmp) |= ((UInt8)(val)); \
        } while (0)

/* Clears the tx buffer. For correct operation, the rtz sequence should not be "busy" when clearing the buffer */
#define GP_WB_RTZ_CLR_TX_DATA_BUFFER(offset) \
        ((RTZ_REGMAP_T *) (offset))->triggers.reg32[0] = (0x00000002)

#define GP_WB_SET_RTZ_CLR_TX_DATA_BUFFER_TO_TRIGGERS(tmp, val) do { \
          GP_WB_SIZE_CHECK_U8(tmp); \
          GP_WB_RANGE_CHECK(val, 0x01); \
          (tmp) &= 0x01; \
          (tmp) |= (((UInt8)(val)) << 1); \
        } while (0)


/* register access functions for RTZ_UNMASKED_INTERRUPTS */
#define GP_WB_READ_RTZ_UNMASKED_INTERRUPTS(offset) \
        ((UInt8)((RTZ_REGMAP_T *) (offset))->unmasked_interrupts.reg32[0])

/* Unmasked interrupt flag indicating that data was read from an empty buffer. This indicates the block is not configured correctly (data is not supplied fast enough) */
#define GP_WB_READ_RTZ_UNMASKED_BUFFER_UNDERRUN_INTERRUPT(offset) \
        ((UInt8)((((RTZ_REGMAP_T *) (offset))->unmasked_interrupts.reg32[0]) & 0x01))

#define GP_WB_GET_RTZ_UNMASKED_BUFFER_UNDERRUN_INTERRUPT_FROM_UNMASKED_INTERRUPTS(tmp) \
        ((tmp) & 0x01)

/* Unmasked interrupt flag indicating a full sequence was completed. Needs to be actively cleared */
#define GP_WB_READ_RTZ_UNMASKED_SEQUENCE_DONE_INTERRUPT(offset) \
        ((UInt8)(((((RTZ_REGMAP_T *) (offset))->unmasked_interrupts.reg32[0]) >> 1) & 0x01))

#define GP_WB_GET_RTZ_UNMASKED_SEQUENCE_DONE_INTERRUPT_FROM_UNMASKED_INTERRUPTS(tmp) \
        (((tmp) >> 1) & 0x01)

/* Status and unmasked interrupt flag for TX buffer not full. The interrupt is cleared implicitly when writing new TX data fills the buffer. */
#define GP_WB_READ_RTZ_UNMASKED_TX_NOT_FULL_INTERRUPT(offset) \
        ((UInt8)(((((RTZ_REGMAP_T *) (offset))->unmasked_interrupts.reg32[0]) >> 2) & 0x01))

#define GP_WB_GET_RTZ_UNMASKED_TX_NOT_FULL_INTERRUPT_FROM_UNMASKED_INTERRUPTS(tmp) \
        (((tmp) >> 2) & 0x01)


/* register access functions for RTZ_CLR_INTERRUPTS */
#define GP_WB_WRITE_RTZ_CLR_INTERRUPTS(offset, val) \
      ((RTZ_REGMAP_T *) (offset))->clr_interrupts.reg32[0] = (val)

/* Clears the underrun interrupt (bad usage condition) */
#define GP_WB_RTZ_CLR_BUFFER_UNDERRUN_INTERRUPT(offset) \
        ((RTZ_REGMAP_T *) (offset))->clr_interrupts.reg32[0] = (0x00000001)

#define GP_WB_SET_RTZ_CLR_BUFFER_UNDERRUN_INTERRUPT_TO_CLR_INTERRUPTS(tmp, val) do { \
          GP_WB_SIZE_CHECK_U8(tmp); \
          GP_WB_RANGE_CHECK(val, 0x01); \
          (tmp) &= 0x02; \
          (tmp) |= ((UInt8)(val)); \
        } while (0)

/* Clears the sequence done interrupt */
#define GP_WB_RTZ_CLR_SEQUENCE_DONE_INTERRUPT(offset) \
        ((RTZ_REGMAP_T *) (offset))->clr_interrupts.reg32[0] = (0x00000002)

#define GP_WB_SET_RTZ_CLR_SEQUENCE_DONE_INTERRUPT_TO_CLR_INTERRUPTS(tmp, val) do { \
          GP_WB_SIZE_CHECK_U8(tmp); \
          GP_WB_RANGE_CHECK(val, 0x01); \
          (tmp) &= 0x01; \
          (tmp) |= (((UInt8)(val)) << 1); \
        } while (0)


