/***************************
 * regmap: timerxl
 ***************************/

/* clock for main counter is prescaled by 2**(prescale_div) */
#define GP_WB_READ_TIMERXL_TIMERXL32_PRESCALER_DIV(offset) \
        ((UInt8)((((TIMERXL_REGMAP_T *) (offset))->unnamed_reg_timerxl_0x0000.reg32[0]) & 0x0F))

#define GP_WB_WRITE_TIMERXL_TIMERXL32_PRESCALER_DIV(offset, val) do { \
          GP_WB_RANGE_CHECK(val, 0x0F); \
          GP_WB_CHECK_OFFSET_TIMERXL(offset); \
          UInt32 halprop_h_tmp = (((TIMERXL_REGMAP_T *) (offset))->unnamed_reg_timerxl_0x0000.reg32[0]); \
          halprop_h_tmp = (halprop_h_tmp & ~(0x0000000f)) | ((((val)) << 0) & (0x0000000f)); \
          ((TIMERXL_REGMAP_T *) (offset))->unnamed_reg_timerxl_0x0000.reg32[0] = halprop_h_tmp; \
        } while (0)

/* defines what modes is used for incrementing the timer counter (prescaled, or count mode using external quic trigger) */
#define GP_WB_READ_TIMERXL_TIMERXL32_COUNT_MODE(offset) \
        ((UInt8)(((((TIMERXL_REGMAP_T *) (offset))->unnamed_reg_timerxl_0x0000.reg32[0]) >> 4) & 0x01))

#define GP_WB_WRITE_TIMERXL_TIMERXL32_COUNT_MODE(offset, val) do { \
          GP_WB_RANGE_CHECK(val, 0x01); \
          GP_WB_CHECK_OFFSET_TIMERXL(offset); \
          UInt32 halprop_h_tmp = (((TIMERXL_REGMAP_T *) (offset))->unnamed_reg_timerxl_0x0000.reg32[0]); \
          halprop_h_tmp = (halprop_h_tmp & ~(0x00000010)) | ((((val) << 4) << 0) & (0x00000010)); \
          ((TIMERXL_REGMAP_T *) (offset))->unnamed_reg_timerxl_0x0000.reg32[0] = halprop_h_tmp; \
        } while (0)


/* starts the timer */
#define GP_WB_TIMERXL_TIMERXL32_START(offset) \
        ((TIMERXL_REGMAP_T *) (offset))->unnamed_reg_timerxl_0x0004.reg32[0] = (0x00000001)

/* stops the timer */
#define GP_WB_TIMERXL_TIMERXL32_STOP(offset) \
        ((TIMERXL_REGMAP_T *) (offset))->unnamed_reg_timerxl_0x0004.reg32[0] = (0x00000002)

/* resets the timer value to 0 (including prescaler) */
#define GP_WB_TIMERXL_TIMERXL32_RESET(offset) \
        ((TIMERXL_REGMAP_T *) (offset))->unnamed_reg_timerxl_0x0004.reg32[0] = (0x00000004)

/* Presets the timer value to the value set by the cc 0 compare value */
#define GP_WB_TIMERXL_TIMERXL32_PRESET(offset) \
        ((TIMERXL_REGMAP_T *) (offset))->unnamed_reg_timerxl_0x0004.reg32[0] = (0x00000008)

/* clears the timer overflow interrupt */
#define GP_WB_TIMERXL_TIMERXL32_CLR_OVERFLOW_INTERRUPT(offset) \
        ((TIMERXL_REGMAP_T *) (offset))->unnamed_reg_timerxl_0x0004.reg32[0] = (0x00000010)


/* Interrupt set when timer overflow happens (can be when reaching the end of the range or on a clr on compare event) */
#define GP_WB_READ_TIMERXL_UNMASKED_TIMERXL32_OVERFLOW_INTERRUPT(offset) \
