#define GP_WB_GET_UART_RX_ENABLE_FROM_CONF(tmp) \
        (((tmp) >> 8) & 0x01)

#define GP_WB_WRITE_UART_RX_ENABLE(offset, val) do { \
          GP_WB_RANGE_CHECK(val, 0x01); \
          GP_WB_CHECK_OFFSET_UART(offset); \
          UInt32 halprop_h_tmp = (((UART_REGMAP_T *) (offset))->conf.reg32[0]); \
          halprop_h_tmp = (halprop_h_tmp & ~(0x00000100)) | ((((val)) << 8) & (0x00000100)); \
          ((UART_REGMAP_T *) (offset))->conf.reg32[0] = halprop_h_tmp; \
        } while (0)

#define GP_WB_SET_UART_RX_ENABLE_TO_CONF(tmp, val) do { \
          GP_WB_SIZE_CHECK_U16(tmp); \
          GP_WB_RANGE_CHECK(val, 0x01); \
          (tmp) &= 0x0EFF; \
          (tmp) |= (((UInt16)(val)) << 8); \
        } while (0)

/* Enables the tx fifo interrupts. Allows SW to stop interrupt generation from the Spi master when the UART is not needed. */
#define GP_WB_READ_UART_ENABLE_TX_INTERRUPTS(offset) \
        ((UInt8)(((((UART_REGMAP_T *) (offset))->conf.reg32[0]) >> 9) & 0x01))

#define GP_WB_GET_UART_ENABLE_TX_INTERRUPTS_FROM_CONF(tmp) \
        (((tmp) >> 9) & 0x01)

#define GP_WB_WRITE_UART_ENABLE_TX_INTERRUPTS(offset, val) do { \
          GP_WB_RANGE_CHECK(val, 0x01); \
          GP_WB_CHECK_OFFSET_UART(offset); \
          UInt32 halprop_h_tmp = (((UART_REGMAP_T *) (offset))->conf.reg32[0]); \
          halprop_h_tmp = (halprop_h_tmp & ~(0x00000200)) | ((((val) << 1) << 8) & (0x00000200)); \
          ((UART_REGMAP_T *) (offset))->conf.reg32[0] = halprop_h_tmp; \
        } while (0)

#define GP_WB_SET_UART_ENABLE_TX_INTERRUPTS_TO_CONF(tmp, val) do { \
          GP_WB_SIZE_CHECK_U16(tmp); \
          GP_WB_RANGE_CHECK(val, 0x01); \
          (tmp) &= 0x0DFF; \
          (tmp) |= (((UInt16)(val)) << 9); \
        } while (0)

/* In case of the HW MSI interface (stream_to_regmap = 0), bit_reverse the data part of the reply. This feature was added for Lime. */
#define GP_WB_READ_UART_BIT_REVERSE_REPLY(offset) \
        ((UInt8)(((((UART_REGMAP_T *) (offset))->conf.reg32[0]) >> 10) & 0x01))

#define GP_WB_GET_UART_BIT_REVERSE_REPLY_FROM_CONF(tmp) \
        (((tmp) >> 10) & 0x01)

#define GP_WB_WRITE_UART_BIT_REVERSE_REPLY(offset, val) do { \
          GP_WB_RANGE_CHECK(val, 0x01); \
          GP_WB_CHECK_OFFSET_UART(offset); \
          UInt32 halprop_h_tmp = (((UART_REGMAP_T *) (offset))->conf.reg32[0]); \
          halprop_h_tmp = (halprop_h_tmp & ~(0x00000400)) | ((((val) << 2) << 8) & (0x00000400)); \
          ((UART_REGMAP_T *) (offset))->conf.reg32[0] = halprop_h_tmp; \
        } while (0)

#define GP_WB_SET_UART_BIT_REVERSE_REPLY_TO_CONF(tmp, val) do { \
          GP_WB_SIZE_CHECK_U16(tmp); \
          GP_WB_RANGE_CHECK(val, 0x01); \
          (tmp) &= 0x0BFF; \
          (tmp) |= (((UInt16)(val)) << 10); \
        } while (0)

/* When set the UART transmitter will stop sending data when the receiving device indicates no more data can be received (CTS/RTS handling). Remark that RTS generation is always done through SW, through a GPIO */
#define GP_WB_READ_UART_ENABLE_HW_FLOW_CONTROL(offset) \
        ((UInt8)(((((UART_REGMAP_T *) (offset))->conf.reg32[0]) >> 11) & 0x01))

#define GP_WB_GET_UART_ENABLE_HW_FLOW_CONTROL_FROM_CONF(tmp) \
        (((tmp) >> 11) & 0x01)

#define GP_WB_WRITE_UART_ENABLE_HW_FLOW_CONTROL(offset, val) do { \
          GP_WB_RANGE_CHECK(val, 0x01); \
          GP_WB_CHECK_OFFSET_UART(offset); \
          UInt32 halprop_h_tmp = (((UART_REGMAP_T *) (offset))->conf.reg32[0]); \
          halprop_h_tmp = (halprop_h_tmp & ~(0x00000800)) | ((((val) << 3) << 8) & (0x00000800)); \
          ((UART_REGMAP_T *) (offset))->conf.reg32[0] = halprop_h_tmp; \
        } while (0)

#define GP_WB_SET_UART_ENABLE_HW_FLOW_CONTROL_TO_CONF(tmp, val) do { \
          GP_WB_SIZE_CHECK_U16(tmp); \
          GP_WB_RANGE_CHECK(val, 0x01); \
          (tmp) &= 0x07FF; \
          (tmp) |= (((UInt16)(val)) << 11); \
        } while (0)


/* Status flag for UART RX not busy. Active when no RX transfer is ongoing. */
#define GP_WB_READ_UART_RX_NOT_BUSY(offset) \
        ((UInt8)(((UART_REGMAP_T *) (offset))->rx_not_busy.reg32[0]))


/* register access functions for UART_UNMASKED_INTERRUPTS */
#define GP_WB_READ_UART_UNMASKED_INTERRUPTS(offset) \
        ((UInt8)((UART_REGMAP_T *) (offset))->unmasked_interrupts.reg32[0])

/* Event and unmasked interrupt flag for the occurrence of a rx framing error. Set when the (first) stop bit of a received frame was not 1. Cleared explicitly by the SW. */
#define GP_WB_READ_UART_UNMASKED_RX_FRAMING_ERROR_INTERRUPT(offset) \
        ((UInt8)((((UART_REGMAP_T *) (offset))->unmasked_interrupts.reg32[0]) & 0x01))

#define GP_WB_GET_UART_UNMASKED_RX_FRAMING_ERROR_INTERRUPT_FROM_UNMASKED_INTERRUPTS(tmp) \
        ((tmp) & 0x01)

/* Status and unmasked interrupt flag for RX buffer not empty. The interrupt is cleared implicitly when reading the last RX data from the buffer. */
#define GP_WB_READ_UART_UNMASKED_RX_NOT_EMPTY_INTERRUPT(offset) \
        ((UInt8)(((((UART_REGMAP_T *) (offset))->unmasked_interrupts.reg32[0]) >> 1) & 0x01))

#define GP_WB_GET_UART_UNMASKED_RX_NOT_EMPTY_INTERRUPT_FROM_UNMASKED_INTERRUPTS(tmp) \
        (((tmp) >> 1) & 0x01)

/* Event and unmasked interrupt flag for the occurrence of a rx data buffer overrun event. Set when the rx data buffer is full and new rx data is available. Cleared explicitly by the SW. */
#define GP_WB_READ_UART_UNMASKED_RX_OVERRUN_INTERRUPT(offset) \
        ((UInt8)(((((UART_REGMAP_T *) (offset))->unmasked_interrupts.reg32[0]) >> 2) & 0x01))

#define GP_WB_GET_UART_UNMASKED_RX_OVERRUN_INTERRUPT_FROM_UNMASKED_INTERRUPTS(tmp) \
        (((tmp) >> 2) & 0x01)

/* Event and unmasked interrupt flag for the occurrence of a rx parity error. Set when the parity checking is enabled and the received parity bit does not match with the calculated. Cleared explicitly by the SW. */
#define GP_WB_READ_UART_UNMASKED_RX_PARITY_ERROR_INTERRUPT(offset) \
        ((UInt8)(((((UART_REGMAP_T *) (offset))->unmasked_interrupts.reg32[0]) >> 3) & 0x01))

#define GP_WB_GET_UART_UNMASKED_RX_PARITY_ERROR_INTERRUPT_FROM_UNMASKED_INTERRUPTS(tmp) \
        (((tmp) >> 3) & 0x01)

/* Status and unmasked interrupt flag for UART TX not busy. The interrupt is cleared implicitly when writing new TX data. Active when no TX transfer ongoing and no data in TX buffer. */
#define GP_WB_READ_UART_UNMASKED_TX_NOT_BUSY_INTERRUPT(offset) \
        ((UInt8)(((((UART_REGMAP_T *) (offset))->unmasked_interrupts.reg32[0]) >> 4) & 0x01))

#define GP_WB_GET_UART_UNMASKED_TX_NOT_BUSY_INTERRUPT_FROM_UNMASKED_INTERRUPTS(tmp) \
        (((tmp) >> 4) & 0x01)

/* Status and unmasked interrupt flag for TX buffer not full. The interrupt is cleared implicitly when writing new TX data fills the buffer. */
#define GP_WB_READ_UART_UNMASKED_TX_NOT_FULL_INTERRUPT(offset) \
        ((UInt8)(((((UART_REGMAP_T *) (offset))->unmasked_interrupts.reg32[0]) >> 5) & 0x01))

#define GP_WB_GET_UART_UNMASKED_TX_NOT_FULL_INTERRUPT_FROM_UNMASKED_INTERRUPTS(tmp) \
        (((tmp) >> 5) & 0x01)


/* register access functions for UART_CLR_INTERRUPTS */
#define GP_WB_WRITE_UART_CLR_INTERRUPTS(offset, val) \
      ((UART_REGMAP_T *) (offset))->clr_interrupts.reg32[0] = (val)

/* Clear the rx_framining_error_interrupt. */
#define GP_WB_UART_CLR_RX_FRAMING_ERROR_INTERRUPT(offset) \
        ((UART_REGMAP_T *) (offset))->clr_interrupts.reg32[0] = (0x00000001)

#define GP_WB_SET_UART_CLR_RX_FRAMING_ERROR_INTERRUPT_TO_CLR_INTERRUPTS(tmp, val) do { \
          GP_WB_SIZE_CHECK_U8(tmp); \
          GP_WB_RANGE_CHECK(val, 0x01); \
          (tmp) &= 0x0C; \
          (tmp) |= ((UInt8)(val)); \
        } while (0)

/* Clear the rx_overrun_interrupt. */
#define GP_WB_UART_CLR_RX_OVERRUN_INTERRUPT(offset) \
        ((UART_REGMAP_T *) (offset))->clr_interrupts.reg32[0] = (0x00000004)

#define GP_WB_SET_UART_CLR_RX_OVERRUN_INTERRUPT_TO_CLR_INTERRUPTS(tmp, val) do { \
          GP_WB_SIZE_CHECK_U8(tmp); \
          GP_WB_RANGE_CHECK(val, 0x01); \
          (tmp) &= 0x09; \
          (tmp) |= (((UInt8)(val)) << 2); \
        } while (0)

/* Clear the rx_parity_error_interrupt. */
#define GP_WB_UART_CLR_RX_PARITY_ERROR_INTERRUPT(offset) \
        ((UART_REGMAP_T *) (offset))->clr_interrupts.reg32[0] = (0x00000008)

#define GP_WB_SET_UART_CLR_RX_PARITY_ERROR_INTERRUPT_TO_CLR_INTERRUPTS(tmp, val) do { \
          GP_WB_SIZE_CHECK_U8(tmp); \
          GP_WB_RANGE_CHECK(val, 0x01); \
          (tmp) &= 0x05; \
          (tmp) |= (((UInt8)(val)) << 3); \
        } while (0)

#endif //GP_WB_PROP_H
